import React, { useState } from "react";
import { Accordion } from "react-bootstrap";

const Faqv2 = ({ faqData = [] }) => {
  const [visibleItems, setVisibleItems] = useState(4);
  const [hasMore, setHasMore] = useState(true);

  const handleLoadMore = () => {
    setVisibleItems(visibleItems + 4);
    if (visibleItems + 4 >= faqData?.length) {
      setHasMore(false);
    }
  };
  return (
    <div
      className="faq_rhs-v2 item-start faq_v3"
      style={{
        padding: "0px",
      }}
    >
      <h2 className="about-h3">Frequently Asked Questions</h2>
      <div className="faq_acc_wrapper-v2">
        <Accordion>
          {faqData?.slice(0, visibleItems)?.map((item, index) => (
            <Accordion.Item
              key={index}
              eventKey={index.toString()}
              className="border-0"
              style={{
                border: "none",
                backgroundColor: "var(--gray-100)",
                borderRadius: "0px",
                padding: "0px",
              }}
            >
              <Accordion.Header
                style={{
                  position: "relative",
                  padding: "24px 32px",
                }}
                as={"h3"}
              >
                {/* <style>
                  {`
            
          `}
                </style> */}

                <div>{item.question}</div>
              </Accordion.Header>

              <Accordion.Body
                style={{
                  padding: "20px 32px",
                }}
              >
                {item.answer}
              </Accordion.Body>
            </Accordion.Item>
          ))}
        </Accordion>
      </div>
      {faqData?.length > 4 && hasMore && (
        <div
          role="button"
          tabIndex="0"
          className="decenter_hero_sec_btn d-flex justify-content-center"
          onClick={handleLoadMore}
        >
          <button className="roll-button roll-btn">
            <span>Load More</span>
          </button>
        </div>
      )}
    </div>
  );
};

